// 根据标题搜索古诗
export function searchPoemByTitle(title) {
  return poems.find(poem => poem.title.includes(title))
}

// 获取所有古诗
export function getAllPoems() {
  return poems
}

// 获取必背古诗（保留原功能，但建议改用按学段获取）
export function getRequiredPoems() {
  return poems.filter(poem => poem.required)
}

// 根据作者搜索
export function searchPoemsByAuthor(author) {
  return poems.filter(poem => poem.author.includes(author))
}

// 新增：按学段获取古诗
export function getPoemsByLevel(level) {
  return poems.filter(poem => poem.level === level)
}